private boolean isSafeReplacing(Node node,Node replacing){
  if (!node.isGetprop()) {return true; }
  node = node.getFirstchild();
  if (!node.isName()) {return true; }
  String name = node.getString();
  if (!isNameAssignedTo(name, replacing)) {return false; }
  return true;
}

